        const vCountTri = Math.max(1, Math.round(len / PANEL_W));
        for (let i = 0; i <= vCountTri; i++) {
          const t = i / vCountTri;
          const xMm = wall.start.xMm + t * (wall.end.xMm - wall.start.xMm);
