def _wall_thickness_from_type(
    els: dict[str, Element], wall_type_id: str | None, fallback: float
) -> float:
    if not wall_type_id:
        return fallback
    wt = els.get(wall_type_id)
    if not isinstance(wt, WallTypeElem) or not wt.layers:
        return fallback
    return float(sum(lyr.thickness_mm for lyr in wt.layers)) or fallback


def _validate_wall_stack(components: list, wall_height_mm: float) -> None:
    """Validate stacked-wall components: prefix Σ heightMm must be < wall heightMm."""
    if not components:
        raise ValueError("wall stack must have at least one component")
    prefix_sum = sum(c.height_mm for c in components[:-1])
    if prefix_sum >= wall_height_mm:
        raise ValueError(
            f"wall stack prefix Σ heightMm ({prefix_sum} mm) must be < "
            f"wall heightMm ({wall_height_mm} mm)"
        )


def _validate_wall_lean_taper(
    lean_mm: Vec2Mm | None,
    taper_ratio: float | None,
    wall_height_mm: float,
) -> None:
    if lean_mm is not None:
        magnitude = math.sqrt(lean_mm.x_mm**2 + lean_mm.y_mm**2)
        max_lean = wall_height_mm * math.tan(math.radians(60))
        if magnitude > max_lean:
            raise ValueError(
                f"leanMm magnitude ({magnitude:.1f} mm) exceeds "
                f"wall height × tan(60°) ({max_lean:.1f} mm)"
            )
    if taper_ratio is not None:
        if not (0.1 < taper_ratio < 10.0):
            raise ValueError(f"taperRatio ({taper_ratio}) must be in open interval (0.1, 10)")

