  await page.addInitScript(() => {
    localStorage.setItem('bim.welcome.dismissed', '1');
    localStorage.setItem('bim.onboarding-completed', 'true');
    localStorage.setItem('bim.workspaceLayout', 'split_plan_3d');
  });
  await page.route('**/api/bootstrap', async route => route.fulfill({ status: 200, contentType: 'application/json', body: JSON.stringify({ projects: [{ id: 'p', slug: 'p', title: 'Proof', models: [{ id: MODEL_ID, slug: 'm', revision: 1 }] }] }) }));
  await page.route(`**/api/models/${encodeURIComponent(MODEL_ID)}/snapshot**`, async route => route.fulfill({ status: 200, contentType: 'application/json', body: JSON.stringify({ modelId: MODEL_ID, revision: 1, elements, violations: [] }) }));
  await page.route('**/api/models/*/comments**', async route => route.fulfill({ status: 200, contentType: 'application/json', body: '{}' }));
  await page.route('**/api/models/*/activity**', async route => route.fulfill({ status: 200, contentType: 'application/json', body: '{"events":[]}' }));
  await page.route('**/api/building-presets**', async route => route.fulfill({ status: 200, contentType: 'application/json', body: '{"presets":{"residential":{}}}' }));
  await page.route('**/api/models/*/projection/plan**', async route => route.fulfill({ status: 200, contentType: 'application/json', body: JSON.stringify({ format: 'planProjectionWire_v1', primitives: { format: 'planProjectionPrimitives_v1', walls: [], floors: [], rooms: [], doors: [], windows: [] } }) }));
  await page.goto('http://127.0.0.1:5741/');
  await page.waitForSelector('[data-testid="app-shell"]', { timeout: 30000 });
  await page.waitForTimeout(4500);
  await page.screenshot({ path: path.join(outDir, '01-full-split-3d.png'), fullPage: true });
  const canvases = await page.locator('canvas').count();
  for (let i = 0; i < canvases; i++) {
    const box = await page.locator('canvas').nth(i).boundingBox();
    if (!box || box.width < 200 || box.height < 200) continue;
    await page.locator('canvas').nth(i).screenshot({ path: path.join(outDir, `canvas-${i}.png`) });
  }
  console.log(JSON.stringify({ outDir, canvases }, null, 2));
  await browser.close();
})();
