  const wallOffset = wallPlanOffsetM(wall);
  const off = recessOffsetForOpening(wall, door.alongT);
  group.position.set(
    px + wallOffset.xM + off.dx,
    wallBaseElevationM(wall, elevM),
    pz + wallOffset.zM + off.dz,
  );
  group.rotation.y = wallYaw(wall);
